#include <WeaselIPCData.h>
#include <windows.h>
#include <map>
#include <memory>
#include <string>

namespace weasel {
class Deserializer;

// 解析server回應文本
struct ResponseParser {
  std::map<std::wstring, std::shared_ptr<Deserializer> > deserializers;

  std::wstring* p_commit;
  Context* p_context;
  Status* p_status;
  Config* p_config;
  UIStyle* p_style;

  ResponseParser(std::wstring* commit,
                 Context* context = 0,
                 Status* status = 0,
                 Config* config = 0,
                 UIStyle* style = 0);

  // 重載函數調用運算符, 以扮做ResponseHandler
  bool operator()(LPWSTR buffer, UINT length);

  // 處理一行回應文本
  void Feed(const std::wstring& line);
};

}  // namespace weasel

