867	                .append(L" ")
868	                .append(escape_string(comment_w));
869	          }
870	          body.append(L" ]\n");
871	          if (start <= end) {
872	            body.append(L"ctx.preedit.cursor=")
873	                .append(u8towstring(preedit, start))
874	                .append(L",")
875	                .append(u8towstring(preedit, end))
876	                .append(L",")
877	                .append(u8towstring(preedit, cursor))
878	                .append(L"\n");
879	          }
880	          break;
881	        }
882	      }
883	    }
